FROM Student 
WHERE StuID IN (
    SELECT StuID FROM Voting_record GROUP BY StuID HAVING COUNT(*) > 2
);

SELECT DISTINCT T1.Major 
FROM Student AS T1 
WHERE T1.StuID IN (SELECT T2.StuID FROM Student AS T2 GROUP BY T2.StuID HAVING COUNT(*) < 3);

SELECT Election_Cycle, COUNT(*) AS Num_Voting_Records
FROM Voting_record
GROUP BY Election_Cycle;

SELECT Grape, COUNT(*) as NumberOfWines
FROM wine
GROUP BY Grape;

SELECT AVG(Price), Appelation
FROM wine
GROUP BY Appelation;

SELECT DISTINCT Name 
FROM wine 
ORDER BY Name ASC;

SELECT Name 
FROM wine 
ORDER BY Price ASC;

SELECT AVG(Price), SUM(Cases) 
FROM wine 
WHERE Grape = 'Zinfandel' AND Year = 2009;

SELECT W.Name 
FROM wine AS W 
WHERE W.Year > 2006;

SELECT s.Author, s.Scores 
FROM submission s 
ORDER BY s.Scores ASC;

SELECT s.Author, a.Result 
FROM submission s 
JOIN Acceptance a ON s.Submission_ID = a.Submission_ID;

SELECT DISTINCT Author 
FROM submission 
WHERE Submission_ID NOT IN (SELECT Submission_ID FROM Acceptance);

SELECT COUNT(Code) AS NumOfRepublicGovernments
FROM country
WHERE Code IN (SELECT CountryCode FROM countrylanguage WHERE Language = 'English' AND GovernmentType = 'republic');

SELECT Name 
FROM wrestler 
ORDER BY Days_held DESC;

SELECT Name 
FROM wrestler 
ORDER BY Days_held ASC LIMIT 1;

SELECT DISTINCT Reign 
FROM wrestler 
WHERE Location != 'Tokyo, Japan' AND Reign IS NOT NULL;

SELECT Name 
FROM wrestler 
WHERE Days_held < 100;

SELECT Name 
FROM wrestler 
WHERE Wrestler_ID NOT IN (SELECT Wrestler_ID FROM Elimination);

SELECT MAX(T2.winner_rank) AS best_rank
FROM qualifiers AS T1
JOIN players AS T2 ON T1.winner_id = T2.player_id;

SELECT DISTINCT p.winner_name, p.loser_name 
FROM players p 
WHERE p.winner_hand = 'L' OR p.loser_hand = 'L';

SELECT DISTINCT loser_ioc, winner_ioc 
FROM players 
WHERE (loser_ioc IS NOT NULL OR winner_ioc IS NOT NULL) AND COUNT(*) > 50;
